// ✗ INVALID — conditional hook
function UserProfile({ isLoggedIn }) {
  if (isLoggedIn) {
    // On first render: slots = [useState-slot-0, useEffect-slot-1]
    // If isLoggedIn flips to false: slot-0 is skipped
    // → every following hook reads the wrong slot
    const [user, setUser] = useState(null);
  }
  useEffect(() => { document.title = 'Profile'; }, []);
  // ^ reads slot-0 on second render, not slot-1
}

// ✓ VALID — hook at top level, condition inside
function UserProfile({ isLoggedIn }) {
  const [user, setUser] = useState(null); // always slot 0
  useEffect(() => {
    if (!isLoggedIn) return; // condition inside, not around the hook
    fetchUser().then(setUser);
  }, [isLoggedIn]); // always slot 1
}

// ✗ INVALID — hooks in a loop
function ItemList({ items }) {
  return items.map(item => {
    const [selected, setSelected] = useState(false); // ✗ varies per render
    return <div onClick={() => setSelected(s => !s)}>{item.name}</div>;
  });
}

// ✓ VALID — hook lives in the child component
function Item({ item }) {
  const [selected, setSelected] = useState(false); // top level here
  return <div onClick={() => setSelected(s => !s)}>{item.name}</div>;
}

function ItemList({ items }) {
  return items.map(item => <Item key={item.id} item={item} />);
}

// ✗ INVALID — hook inside a nested helper
function SearchBox() {
  function handleSearch() {
    const [results, setResults] = useState([]); // ✗ not on every render
  }
  return <input onChange={handleSearch} />;
}

// ✓ VALID — hook at top level, pass value to handler
function SearchBox() {
  const [results, setResults] = useState([]); // top level
  function handleSearch(e) {
    fetchResults(e.target.value).then(setResults); // use setter in handler
  }
  return <input onChange={handleSearch} />;
}

// ✓ Pattern: hook unconditional, skip logic inside
function DataPanel({ enabled }) {
  const [data, setData] = useState(null);

  useEffect(() => {
    if (!enabled) return; // early return, not early hook skip
    fetchData().then(setData);
  }, [enabled]);

  if (!enabled) return null; // conditional render, not conditional hook
  return <div>{data}</div>;
}

// ✗ INVALID — hook in a plain utility function
function formatAndCache(value) {
  const [cached, setCached] = useState(value); // ✗ throws at runtime
  return cached;
}

// ✗ INVALID — hook in a class component method
class MyClass extends React.Component {
  doSomething() {
    useEffect(() => {}); // ✗ throws at runtime
  }
}

// ✗ INVALID — hook in an event listener
document.addEventListener('click', () => {
  const [x] = useState(0); // ✗ no fiber context here
});

// ✓ Custom hook — can call hooks, reusable across components
function useWindowSize() {
  const [size, setSize] = useState({ width: window.innerWidth, height: window.innerHeight });
  useEffect(() => {
    const handler = () => setSize({ width: window.innerWidth, height: window.innerHeight });
    window.addEventListener('resize', handler);
    return () => window.removeEventListener('resize', handler);
  }, []);
  return size;
}

// ✓ Called from a function component
function Header() {
  const { width } = useWindowSize();
  return <nav style={{ fontSize: width < 600 ? 14 : 16 }}>...</nav>;
}

// ✓ Called from another custom hook
function useResponsiveLayout() {
  const { width } = useWindowSize(); // hook calling hook — valid
  return width < 600 ? 'mobile' : 'desktop';
}

// .eslintrc.json
{
  "plugins": ["react-hooks"],
  "rules": {
    "react-hooks/rules-of-hooks": "error",
    "react-hooks/exhaustive-deps": "warn"
  }
}

// ✗ conditional state — invalid
function Profile({ userId }) {
  if (!userId) {
    return <Login />; // early return is fine...
  }
  const [profile, setProfile] = useState(null); // ✗ not at top level
}

// ✓ unconditional state — valid
function Profile({ userId }) {
  const [profile, setProfile] = useState(null); // always runs
  if (!userId) return <Login />;                // early return after hooks
  // ...
}

// ✗ useEffect inside a plain helper
function setupSubscription(channel) {    // not a hook name
  useEffect(() => {                       // ✗ linter won't flag this as a hook
    const sub = subscribe(channel);
    return () => unsubscribe(sub);
  }, [channel]);
}

// ✓ renamed to a custom hook
function useSubscription(channel) {      // 'use' prefix = hook
  useEffect(() => {
    const sub = subscribe(channel);
    return () => unsubscribe(sub);
  }, [channel]);
}

// ✗ useState inside .map — hook count varies with list length
function TagList({ tags }) {
  return tags.map(tag => {
    const [active, setActive] = useState(false); // ✗
    return <span onClick={() => setActive(a => !a)}>{tag}</span>;
  });
}

// ✓ state in a child component
function Tag({ label }) {
  const [active, setActive] = useState(false); // top level
  return <span onClick={() => setActive(a => !a)}>{label}</span>;
}
function TagList({ tags }) {
  return tags.map(tag => <Tag key={tag} label={tag} />);
}

// Wrap root in StrictMode to surface hidden violations
react-dom/client.createRoot(document.getElementById('root')).render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

// DevTools shows hooks in call order — example component
function SearchBox({ query }) {
  // DevTools: State (query) = 'react'
  const [results, setResults] = useState([]);
  // DevTools: State (results) = []

  // DevTools: Effect (search)
  useEffect(() => {
    search(query).then(setResults);
  }, [query]);

  // DevTools: custom useDebounce hook with its own State slot
  const debounced = useDebounce(query, 300);
  return <ResultList items={results} />;
}

// use() may appear inside a conditional — React 19 only
function UserAvatar({ userId }) {
  if (!userId) return <DefaultAvatar />;  // early return before use()

  // use() inside a branch — valid only for use(), not useState/useEffect
  const user = use(fetchUser(userId));
  return <img src={user.avatar} alt={user.name} />;
}

// All other hooks still follow Rule 1
function BadExample({ show }) {
  if (show) {
    const [x] = useState(0); // ✗ still invalid for useState
  }
}
